import React, { useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import InfiniteScroll from 'react-infinite-scroll-component';
import axios from 'axios';
import { Card, Modal } from 'react-bootstrap';

const CollabitImageGalley = ({ images, loading, fetchImages, hasMore }) => {
  return (
    <InfiniteScroll
      dataLength={images.length}
      next={() => fetchImages()}
      hasMore={hasMore}
      loader={
        <p />
      }
    >
      <Card className="image-grid">
        {!loading
          ? images.map(galleryImage => (
              <CollabitImage key={galleryImage.number} image={galleryImage} />
            ))
          : ''}
      </Card>
    </InfiniteScroll>
  );
};

const CollabitImage = props => {
  const [modalShow, setModalShow] = useState(false);
  const { image } = props;
  return (
    <div
      className="image-item"
      key={'image-' + image.id}
    >
      <img
        src={image.thumbnail}
        alt={image.name}
        onClick={() => setModalShow(true)}
      />
      <p>
        #{image.id}
      </p>

      <CollabitsModal
        image={image}
        show={modalShow}
        onHide={() => setModalShow(false)}
      />
    </div>
  );
};

function CollabitsModal(props) {
  const { image } = props;
  return (
    <Modal
      {...props}
      size="md"
      className="collabits-modal"
      aria-labelledby="contained-modal-title-vcenter"
      centered
    >
      <Modal.Header closeButton>
        <Modal.Title id="contained-modal-title-vcenter">
          Collabit #{image.id}
        </Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <div key={image.id}>
          <img
            className="img-fluid"
            src={image.image}
            alt={['mage.tags']}
          />
        </div>
      </Modal.Body>
      <Modal.Footer className="float-left collabit-modal-tags">
        <p className="modal-tags" key={image.id + 'footer-artist'}>
          {' '}
          {image.artist}{' '}
        </p>
        <br />
        <p className="modal-tags" key={image.id + 'footer-desc'}>
          {' '}
          {image.description}{' '}
        </p>
        <br />
        <p className="modal-tags" key={image.id + 'footer-cbit'}>
          {' '}
          CBIT #{image.cbit}{' '}
        </p>
        {image.source && <br />}
        {image.source && (
          <a
            className="modal-tags"
            href={image.source}
            key={image.id + 'footer-source'}
          >
            {' '}
            Source!{' '}
          </a>
        )}
      </Modal.Footer>
    </Modal>
  );
}

const CollabitsImageProvider = props => {
  // Hold state
  const { searchResult, multiSelections, hasMore } = props;
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [counter, setCounter] = useState(0);

  // Fetch images on component mount
  useEffect(() => {
    if (multiSelections && multiSelections.length === 0) {
      setImages([]);
      setLoading(false);
      setCounter(0);
      fetchImages();
    } else if (searchResult && searchResult.length !== 0) {
      setImages(searchResult);
      setLoading(false);
      setCounter(0);
    } else if (searchResult.length === 0) {
      setImages([]);
      setLoading(false);
      setCounter(0);
    }
  }, [multiSelections, searchResult]);

  // API endpoint
  const endpoint = 'https://backend.cardanobits.art:9364';
  // Fetch Images from functions
  const fetchImages = () => {
    if (multiSelections && multiSelections.length !== 0) {
      const arratOfTags = multiSelections.map(a => a.label);
      axios(
        endpoint +
          `/tags/collabits?tags=${arratOfTags}&pageNumber=${counter + 1}`
      ).then(res => {
        setImages([...images, ...res.data]);
        setLoading(false);
        setCounter(counter + 1);
      });
    } else {
      axios(endpoint + '/collabits?number=' + counter).then(res => {
        setImages([...images, ...res.data.content]);
        setLoading(false);
        setCounter(counter + 1);
      });
    }
  };

  return (
    <>
      <CollabitImageGalley
        images={images}
        loading={loading}
        fetchImages={fetchImages}
        hasMore={hasMore}
      />
    </>
  );
};

CollabitImageGalley.propTypes = {
  images: PropTypes.array,
  loading: PropTypes.bool,
  fetchImages: PropTypes.func,
  hasMore: PropTypes.bool,
};

export default CollabitsImageProvider;
